export const STANDARDS: EventStd[] = [
  { key: 'mdl', label: '3-Rep Max Deadlift', shortLabel: 'Deadlift', unit: 'lb', dir: 'high', isTime: false, rows: MDL_ROWS },
  { key: 'spt', label: 'Standing Power Throw', shortLabel: 'Power throw', unit: 'm', dir: 'high', isTime: false, rows: SPT_ROWS },
  { key: 'hrp', label: 'Hand-Release Push-up', shortLabel: 'Push-ups', unit: 'reps', dir: 'high', isTime: false, rows: HRP_ROWS },
  { key: 'sdc', label: 'Sprint-Drag-Carry', shortLabel: 'SDC', unit: 'time', dir: 'low', isTime: true, rows: SDC_ROWS },
  { key: 'plk', label: 'Plank', shortLabel: 'Plank', unit: 'time', dir: 'high', isTime: true, rows: PLK_ROWS },
  { key: 'run', label: 'Two-Mile Run', shortLabel: '2-mile run', unit: 'time', dir: 'low', isTime: true, rows: RUN_ROWS },
];

export type Sex = 'male' | 'female';



export function colIndex(ageIndex: number, sex: Sex): number {
  return 1 + ageIndex * 2 + (sex === 'female' ? 1 : 0);
}


export function timeToSec(v: string): number {
  const m = v.trim().match(/^(\d+):(\d{1,2})$/);
  if (!m) return Number(v);
  return Number(m[1]) * 60 + Number(m[2]);
}


export function secToTime(sec: number): string {
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${String(s).padStart(2, '0')}`;
}

function cellValue(cell: Cell, isTime: boolean): number | null {
  if (cell === null) return null;
  return isTime ? timeToSec(String(cell)) : Number(cell);
}

export function scoreEvent(event: EventStd, sex: Sex, ageIndex: number, raw: number): number {
  const ci = colIndex(ageIndex, sex);
  let best = 0;
  for (const row of event.rows) {
    const pts = row[0] as number;
    const val = cellValue(row[ci], event.isTime);
    if (val === null) continue;
    const meets = event.dir === 'high' ? raw >= val : raw <= val;
    if (meets && pts > best) best = pts;
  }
  return best;
}
